code = """import json
import os

# Load all articles from the file
file_path = locals()['var_functions.query_db:32']
with open(file_path, 'r') as f:
    articles = json.load(f)

print('Total articles: {}'.format(len(articles)))

# Define sports keywords
sports_words = [
    'sports','football','soccer','basketball','baseball','tennis','golf',
    'racing','olympic','game','team','player','coach','match'
]

sports_list = []
for article in articles:
    text = article['title'].lower() + ' ' + article['description'].lower()
    for word in sports_words:
        if word in text:
            sports_list.append({
                'title': article['title'],
                'length': len(article['description'])
            })
            break

if sports_list:
    longest = max(sports_list, key=lambda x: x['length'])
    result = longest['title']
else:
    result = 'No sports articles found'

print('Found {} sports articles'.format(len(sports_list)))
if sports_list:
    print('Longest: "{}" ({} chars)'.format(result[:60], longest['length']))

print('__RESULT__:')
print(json.dumps(result))"""

